Implementasi Observer Pattern yang aman dan efisien untuk Python. Kode ini mencakup penanganan *threading* untuk mencegah *race condition* dan manajemen memori yang tepat.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import threading
import weakref

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject:
    def __init__(self):
        self._observers: List[Observer] = []
        self._lock = threading.Lock()
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        """Menambahkan observer dengan keamanan thread."""
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)

    def detach(self, observer: Observer) -> None:
        """Menghapus observer untuk mencegah memory leak."""
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)

    def notify(self) -> None:
        """Memberi notifikasi ke semua observer yang terdaftar."""
        with self._lock:
            # Copy list untuk menghindari error jika observer mengubah list saat iterasi
            observers = self._observers[:] 

        for observer in observers:
            try:
                observer.update(self)
            except Exception as e:
                # Log error tanpa menghentikan notifikasi ke observer lain
                print(f"Error notifying observer: {e}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

class ConcreteObserver(Observer):
    def __init__(self, name: str):
        self.name = name

    def update(self, subject: Subject) -> None:
        print(f"[{self.name}] State updated to: {subject.get_state()}")

# Contoh Penggunaan
if __name__ == "__main__":
    subject = Subject()
    obs1 = ConcreteObserver("Observer-1")
    obs2 = ConcreteObserver("Observer-2")

    subject.attach(obs1)
    subject.attach(obs2)

    subject.set_state("SECURE_STATE_01")

    subject.detach(obs1)
    subject.set_state("SECURE_STATE_02")
```

### Catatan Teknis & Keamanan:

1.  **Thread Safety**: Menggunakan `threading.Lock` pada metode `attach`, `detach`, dan `notify`. Ini krusial jika aplikasi berjalan di lingkungan multithreading (seperti server web) untuk mencegah *race condition*.
2.  **Isolasi Error**: Blok `try-except` di dalam `notify` memastikan jika satu observer gagal (crash), observer lain tetap menerima notifikasi. Ini mencegah *Denial of Service* lokal pada sistem event.
3.  **Memory Management**: Pastikan memanggil `detach` ketika observer tidak lagi dibutuhkan. Untuk aplikasi skala besar, pertimbangkan menggunakan `weakref` pada list observer untuk mencegah *circular reference* yang menghambat *Garbage Collector*.
4.  **Validasi Input**: Pada implementasi produksi, validasi objek `observer` sebelum ditambahkan untuk memastikan mereka mematuhi interface yang diharapkan.

⚠️ **PERINGATAN KEAMANAN:** Jangan pernah menggunakan fungsi bawaan `eval()` untuk mengeksekusi input user secara langsung. Itu adalah celah keamanan kritis (Remote Code Execution/RCE) yang memungkinkan attacker menjalankan arbitary code di server Anda.

Gunakan pendekatan **Abstract Syntax Tree (AST)** untuk memvalidasi dan membatasi operasi yang diperbolehkan. Berikut implementasi aman menggunakan whitelist node:

```python
import ast
import operator

class SafeMathEvaluator:
    # Whitelist operator yang diizinkan
    OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
    }

    def eval_expr(self, expression: str) -> float:
        try:
            # Parse expression menjadi AST mode 'eval'
            node = ast.parse(expression, mode='eval').body
            return self._eval_node(node)
        except Exception as e:
            raise ValueError(f"Invalid expression: {e}")

    def _eval_node(self, node):
        # Whitelist tipe node yang aman
        if isinstance(node, ast.Constant): # Python 3.8+
            return node.value
        elif isinstance(node, ast.Num): # Fallback untuk Python < 3.8
            return node.n
        elif isinstance(node, ast.BinOp):
            left = self._eval_node(node.left)
            right = self._eval_node(node.right)
            op_type = type(node.op)

            if op_type not in self.OPERATORS:
                raise ValueError(f"Operator {op_type} not allowed")

            return self.OPERATORS[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = self._eval_node(node.operand)
            op_type = type(node.op)

            if op_type not in self.OPERATORS:
                raise ValueError(f"Operator {op_type} not allowed")

            return self.OPERATORS[op_type](operand)
        else:
            # Tolak segala sesuatu yang bukan math dasar (fungsi, variabel, dll)
            raise TypeError(f"Node type {type(node)} not allowed")

# Usage
if __name__ == "__main__":
    evaluator = SafeMathEvaluator()

    # Aman
    print(evaluator.eval_expr("2 + 3 * 4"))  # Output: 14

    # Dangerous & Will Be Blocked
    try:
        evaluator.eval_expr("__import__('os').system('id')") 
    except Exception as e:
        print(f"Blocked: {e}")
```

### Poin Teknis:
1.  **AST Parsing:** Mengubah string menjadi tree struktur tanpa mengeksekusinya.
2.  **Node Whitelisting:** Hanya `Constant`, `BinOp`, dan `UnaryOp` yang diterima. Fungsi (`ast.Call`), variabel (`ast.Name`), dan atribut (`ast.Attribute`) secara otomatis ditolak.
3.  **Operator Mapping:** Operasi matematika dipetakan ke modul `operator` standar Python, bukan dieksekusi sebagai kode Python mentah.

Implementasi ini memitigasi risiko RCE sambil tetap memungkinkan kalkulasi matematika dasar. Untuk kebutuhan kompleks, pertimbangkan library khusus seperti `simpleeval`.

Berikut adalah implementasi fungsi Python untuk melakukan diff dua dictionary secara rekursif. Fungsi ini dirancang untuk efisiensi dan kejelasan struktur perubahan (added, removed, changed).

```python
from typing import Any, Dict, Union

def diff_dicts(dict1: Dict[str, Any], dict2: Dict[str, Any]) -> Dict[str, Any]:
    """
    Membandingkan dua dictionary secara rekursif.
    Returns: Dictionary yang berisi status perubahan (added, removed, changed).
    """
    diff = {}
    keys = set(dict1.keys()) | set(dict2.keys())

    for key in keys:
        val1 = dict1.get(key)
        val2 = dict2.get(key)

        # Key hanya ada di dict2
        if key not in dict1:
            diff[key] = {"status": "added", "value": val2}

        # Key hanya ada di dict1
        elif key not in dict2:
            diff[key] = {"status": "removed", "value": val1}

        # Kedua key ada, cek tipe data untuk rekursi
        elif isinstance(val1, dict) and isinstance(val2, dict):
            nested_diff = diff_dicts(val1, val2)
            if nested_diff:
                diff[key] = {"status": "changed", "diff": nested_diff}

        # Value berbeda (bukan dict)
        elif val1 != val2:
            diff[key] = {"status": "changed", "old": val1, "new": val2}

    return diff

# Contoh Penggunaan
if __name__ == "__main__":
    config_old = {
        "db": {"host": "localhost", "port": 3306},
        "debug": True
    }
    config_new = {
        "db": {"host": "192.168.1.10", "port": 3306, "user": "admin"},
        "cache": {"enabled": True}
    }

    import json
    print(json.dumps(diff_dicts(config_old, config_new), indent=2))
```

### Catatan Teknis:
1.  **Kompleksitas**: O(N + M) di mana N dan M adalah jumlah kunci pada masing-masing dictionary.
2.  **Tipe Data**: Fungsi ini secara spesifik mengecek `isinstance(..., dict)` sebelum melakukan rekursi. Tipe data lain (list, int, string) dibandingkan langsung menggunakan operator `!=`.
3.  **Keamanan**: Tidak ada side-effect. Fungsi ini murni (pure function), aman untuk digunakan dalam audit konfigurasi atau validasi state sebelum deployment.

